-- User-scoped API keys for admin (id=1) -- Key 1: Expired 5 days ago INSERT INTO api_key (suffix, hashed_key, name, scope, user_id, organization_id, created_at, expires_at, last_used_at, total_requests) VALUES ( 'a1b2', '{bcrypt}$2a$10$TEST_HASH_PLACEHOLDER_KEY_1_NOT_REAL_USE_FOR_DISPLAY_ONLY_a1b2', 'Production Server Key', 'USER', 1, NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '60 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '5 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '6 days', 15234 );
-- Key 2: Expiring in 5 days (approaching expiration) INSERT INTO api_key (suffix, hashed_key, name, scope, user_id, organization_id, created_at, expires_at, last_used_at, total_requests) VALUES ( 'c3d4', '{bcrypt}$2a$10$TEST_HASH_PLACEHOLDER_KEY_2_NOT_REAL_USE_FOR_DISPLAY_ONLY_c3d4', 'Development API Key', 'USER', 1, NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '25 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') + INTERVAL '5 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '2 hours', 8921 );
-- Key 3: No expiration, heavily used INSERT INTO api_key (suffix, hashed_key, name, scope, user_id, organization_id, created_at, expires_at, last_used_at, total_requests) VALUES ( 'e5f6', '{bcrypt}$2a$10$TEST_HASH_PLACEHOLDER_KEY_3_NOT_REAL_USE_FOR_DISPLAY_ONLY_e5f6', 'CI/CD Pipeline Key', 'USER', 1, NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '90 days', NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '30 minutes', 142567 );
-- Key 4: No expiration, never used INSERT INTO api_key (suffix, hashed_key, name, scope, user_id, organization_id, created_at, expires_at, last_used_at, total_requests) VALUES ( 'g7h8', '{bcrypt}$2a$10$TEST_HASH_PLACEHOLDER_KEY_4_NOT_REAL_USE_FOR_DISPLAY_ONLY_g7h8', 'Backup Key (unused)', 'USER', 1, NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '10 days', NULL, NULL, 0 );
-- Additional user keys for other test users -- Alice: Active key INSERT INTO api_key (suffix, hashed_key, name, scope, user_id, organization_id, created_at, expires_at, last_used_at, total_requests) SELECT 'i9j0', '{bcrypt}$2a$10$TEST_HASH_PLACEHOLDER_KEY_5_NOT_REAL_USE_FOR_DISPLAY_ONLY_i9j0', 'Alice Personal Key', 'USER', (SELECT id FROM "user" WHERE email = 'alice.anderson@example.com'), NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '20 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') + INTERVAL '30 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '1 day', 523;
-- Bob: Expired key INSERT INTO api_key (suffix, hashed_key, name, scope, user_id, organization_id, created_at, expires_at, last_used_at, total_requests) SELECT 'k1l2', '{bcrypt}$2a$10$TEST_HASH_PLACEHOLDER_KEY_6_NOT_REAL_USE_FOR_DISPLAY_ONLY_k1l2', 'Bob Old Key', 'USER', (SELECT id FROM "user" WHERE email = 'bob.brown@example.com'), NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '45 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '15 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '16 days', 1089;

-- Acme Corp: Active key, no expiry INSERT INTO api_key (suffix, hashed_key, name, scope, user_id, organization_id, created_at, expires_at, last_used_at, total_requests) SELECT 'm3n4', '{bcrypt}$2a$10$TEST_HASH_PLACEHOLDER_KEY_7_NOT_REAL_USE_FOR_DISPLAY_ORG1_m3n4', 'Acme Production API', 'ORGANIZATION', 1, (SELECT id FROM organization WHERE slug = 'acme-corp'), (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '28 days', NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '1 hour', 89432;
